def solve(equation):
    import re
    def eval_expr(expr):
        res = [0, 0]
        matches = re.finditer(r'([+-]?)(\d*)(x?)', expr)
        for match in matches:
            sign, val, var = match.groups()
            if not sign and not val and not var: continue
            coef = 1
            if val:
                coef = int(val)
            if sign == '-':
                coef = -coef
            if var:
                res[0] += coef
            else:
                res[1] += coef
        return res
    left, right = equation.split('=')
    l_x, l_c = eval_expr(left)
    r_x, r_c = eval_expr(right)
    x = l_x - r_x
    c = r_c - l_c
    if x == 0 and c == 0: return 'Infinite solutions'
    if x == 0: return 'No solution'
    return 'x=' + str(c // x)

